; ノームの洞窟

name = ノームの洞窟
insideName = Cave
level = 16
bgm = hideout
shadow = dark
sky = black
roof = stone
blank = rock
outfield = soil
antiWarp = true
showAllArea = true

; 画像パーツ
━ = soil
　 = soil
☗ = upstair
☖ = gate
︻ = panel
⑵ = bulletin
⑤ = human
⑥ = human
⑦ = human
⑧ = human

; 移動ポイント
(A) = map:ランドン渓谷・谷底, x:25, y:31, way:w, symbol:exit, ask:Leave the dungeon?

